```class Solution {
    public int minStable(int[] nums, int maxC) {
        int n = nums.length;
        int res = n;
        for (int i = 0; i < n; i++) {
            int hcf = nums[i];
            for (int j = i; j < n; j++) {
                hcf = gcd(hcf, nums[j]);
                if (hcf < 2) break;
                res = Math.min(res, j - i + 1);
            }
        }
        return Math.min(res, n - maxC);
    }
    private int gcd(int a, int b) {
        return b == 0 ? a : gcd(b, a % b);
    }
}```
